// 这里的 N 是位数，比如 22
for (int i = 0; i < N; ++i) { 
    for (int mask = 0; mask < (1 << N); ++mask) { 
      	// 从小到大枚举 mask，满足前缀和
      	// 只处理直接子集
        if (mask & (1 << i)) {
            // dp[mask] 表示 mask 及其子集的信息汇总
            // dp[mask ^ (1 << i)] 是把第 i 位去掉后的子集

            // 1. 求和：
            // dp[mask] += dp[mask ^ (1 << i)]; 

            // 2. 求最大值：
            // dp[mask] = max(dp[mask], dp[mask ^ (1 << i)]);

            // 3. CF165E (继承赋值)：
            // if (dp[mask] == -1) dp[mask] = dp[mask ^ (1 << i)];
        }
    }
}

