for (int i = 0; i < N; ++i) {
    for (int mask = 0; mask < (1 << N); ++mask) {
      	// 只处理直接超集
        if (!(mask & (1 << i))) { 
          	// 如果第 i 位是 0
          	// 从对应位是 1 的超集拿数据
            dp[mask] += dp[mask ^ (1 << i)]; 
